#!/usr/bin/env node
/*
 * vm.js - A MIPS32r2 (little-endian, o32) interpreter that runs the
 * `doomgeneric_mips` ELF binary, servicing its system calls (the custom
 * numbering defined in doomgeneric/doomgeneric/my_stdlib.c) so that DOOM boots
 * and renders frames to /tmp/frame.bmp.
 *
 * Usage:  node vm.js [path-to-elf]
 *
 * Environment:
 *   DOOM_FRAMES   number of frames to save before exiting (default 1, 0 = run forever)
 *   DOOM_TRACE    if set, prints a syscall trace to stderr
 *   DOOM_MAXINSN  optional cap on executed instructions (0 = unlimited)
 */
'use strict';

const fs = require('fs');
const path = require('path');

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
const ELF_PATH = process.argv[2] || path.join(__dirname, 'doomgeneric_mips');
const TRACE = !!process.env.DOOM_TRACE;
const FRAME_TARGET = process.env.DOOM_FRAMES !== undefined ? parseInt(process.env.DOOM_FRAMES, 10) : 1;
const MAX_INSN = process.env.DOOM_MAXINSN ? parseInt(process.env.DOOM_MAXINSN, 10) : 0;

const BASE = 0x00400000;                 // lowest mapped virtual address
const MEM_TOP = 0x40c00000;              // top of address space (exclusive)
const MEM_SIZE = MEM_TOP - BASE;         // ~1.08 GiB flat memory
const STACK_TOP = 0x40bffff0;           // initial $sp (16-byte aligned)
const GP_VALUE = 0x0047d090;            // from .reginfo gp_value

// ---------------------------------------------------------------------------
// Memory
// ---------------------------------------------------------------------------
const mem = Buffer.alloc(MEM_SIZE);      // zero-filled (covers .bss)
const M = new Uint8Array(mem.buffer, mem.byteOffset, MEM_SIZE);
const dv = new DataView(mem.buffer, mem.byteOffset, MEM_SIZE);

function inRange(a) { return a >= BASE && a < MEM_TOP; }
function off(a) {
  const o = (a - BASE) >>> 0;
  if (a < BASE || o >= MEM_SIZE) throw new Error('memory access out of range @0x' + (a >>> 0).toString(16));
  return o;
}

function lb(a)  { return dv.getInt8(off(a)); }
function lbu(a) { return M[off(a)]; }
function lh(a)  { return dv.getInt16(off(a), true); }
function lhu(a) { return dv.getUint16(off(a), true); }
function lw(a)  { return dv.getInt32(off(a), true); }
function lwu(a) { return dv.getUint32(off(a), true); }
function sb(a, v) { M[off(a)] = v & 0xff; }
function sh(a, v) { dv.setUint16(off(a), v & 0xffff, true); }
function sw(a, v) { dv.setUint32(off(a), v >>> 0, true); }

// ---------------------------------------------------------------------------
// CPU state
// ---------------------------------------------------------------------------
const R = new Int32Array(32);   // general purpose registers
let HI = 0, LO = 0;
let pc = 0, npc = 0;

// FPU (COP1): 32 x 32-bit registers, 8 condition codes
const FGR = new Int32Array(32);
const FCC = new Uint8Array(8);
const fbuf = new DataView(new ArrayBuffer(8));
function rS(n) { fbuf.setInt32(0, FGR[n], true); return fbuf.getFloat32(0, true); }
function wS(n, v) { fbuf.setFloat32(0, v, true); FGR[n] = fbuf.getInt32(0, true); }
function rD(n) { fbuf.setInt32(0, FGR[n], true); fbuf.setInt32(4, FGR[n + 1], true); return fbuf.getFloat64(0, true); }
function wD(n, v) { fbuf.setFloat64(0, v, true); FGR[n] = fbuf.getInt32(0, true); FGR[n + 1] = fbuf.getInt32(4, true); }

function w(i, v) { if (i !== 0) R[i] = v; }   // write GPR (r0 stays 0)

// 64-bit multiply helpers producing signed HI/LO -------------------------------
function umul(aU, bU) {
  const aL = aU & 0xffff, aH = aU >>> 16;
  const bL = bU & 0xffff, bH = bU >>> 16;
  const ll = aL * bL;
  const lh_ = aL * bH;
  const hl = aH * bL;
  const hh = aH * bH;
  const cross = (ll >>> 16) + (lh_ & 0xffff) + (hl & 0xffff);
  const lo = ((ll & 0xffff) | ((cross & 0xffff) << 16)) >>> 0;
  const hi = (hh + (lh_ >>> 16) + (hl >>> 16) + (cross >>> 16)) >>> 0;
  return [hi, lo];
}
function multSigned(a, b) {
  const aU = a >>> 0, bU = b >>> 0;
  let [hi, lo] = umul(aU, bU);
