}

// guest open flags (see my_stdlib.c)
const GO_RDONLY = 0, GO_WRONLY = 1, GO_RDWR = 2, GO_CREAT = 64, GO_TRUNC = 512, GO_APPEND = 1024;

function guestOpen(pathAddr, flags) {
  const p = cstr(pathAddr);
  let hf = 0;
  const acc = flags & 3;
  if (acc === GO_WRONLY) hf |= fs.constants.O_WRONLY;
  else if (acc === GO_RDWR) hf |= fs.constants.O_RDWR;
  else hf |= fs.constants.O_RDONLY;
  if (flags & GO_CREAT) hf |= fs.constants.O_CREAT;
  if (flags & GO_TRUNC) hf |= fs.constants.O_TRUNC;
  if (flags & GO_APPEND) hf |= fs.constants.O_APPEND;
  let hostFd;
  try {
    hostFd = fs.openSync(p, hf, 0o644);
  } catch (e) {
    if (TRACE) console.error('open FAIL ' + p + ' -> ' + e.code);
    return -2; // -ENOENT
  }
  const gfd = nextFd++;
  fdTable.set(gfd, { hostFd, pos: 0, path: p });
  if (TRACE) console.error('open ' + p + ' flags=0x' + flags.toString(16) + ' -> fd ' + gfd);
  return gfd;
}

function guestRead(fd, bufAddr, count) {
  if (fd === 0) return 0; // stdin: EOF
  const info = fdTable.get(fd);
  if (!info) return -9; // -EBADF
  const o = off(bufAddr);
  let n;
  try {
    n = fs.readSync(info.hostFd, mem, o, count, info.pos);
  } catch (e) { return -5; }
  info.pos += n;
  return n;
}

function guestWrite(fd, bufAddr, count) {
  if (fd === 1 || fd === 2) {
    const o = off(bufAddr);
    const slice = mem.subarray(o, o + count);
    if (fd === 1) process.stdout.write(slice); else process.stderr.write(slice);
    return count;
  }
  const info = fdTable.get(fd);
  if (!info) return -9;
  const o = off(bufAddr);
  let n;
  try {
    n = fs.writeSync(info.hostFd, mem, o, count, info.pos);
  } catch (e) { return -5; }
  info.pos += n;
  // Detect a completed frame write and (optionally) stop.
  if (info.path && /frame\.bmp$/.test(info.path)) {
    framesSaved++;
    if (TRACE) console.error('frame ' + framesSaved + ' saved (' + n + ' bytes) to ' + info.path);
    if (FRAME_TARGET > 0 && framesSaved >= FRAME_TARGET) {
      try { fs.fsyncSync(info.hostFd); } catch (e) {}
      finish(0);
    }
  }
  return n;
}

function guestLseek(fd, offset, whence) {
  const info = fdTable.get(fd);
  if (!info) return -9;
  let np;
  if (whence === 0) np = offset;
  else if (whence === 1) np = info.pos + offset;
  else if (whence === 2) {
    let sz = 0;
    try { sz = fs.fstatSync(info.hostFd).size; } catch (e) {}
    np = sz + offset;
  } else return -22;
  if (np < 0) return -22;
  info.pos = np;
  return np;
}

function guestClose(fd) {
  const info = fdTable.get(fd);
  if (!info) return -9;
  try { fs.closeSync(info.hostFd); } catch (e) {}
  fdTable.delete(fd);
  return 0;
}

function finish(code) {
  running = false;
  exitCode = code | 0;
  // Flush guest std streams already written synchronously; just exit.
  process.exit(exitCode);
}

// System call dispatch. Numbers follow my_stdlib.c (x86-ish numbering that this
// binary reuses for the generic MIPS `syscall` instruction).
function doSyscall() {
  const num = R[2];                 // $v0
  const a0 = R[4], a1 = R[5], a2 = R[6];
  let ret = 0;
  switch (num) {
    case 0:  ret = guestRead(a0, a1, a2 >>> 0); break;               // read
    case 1:  ret = guestWrite(a0, a1, a2 >>> 0); break;              // write
    case 2:  ret = guestOpen(a0, a1); break;                          // open
    case 3:  ret = guestClose(a0); break;                             // close
    case 8:  ret = guestLseek(a0, a1, a2); break;                     // lseek
    case 60: finish(a0); ret = 0; break;                              // exit
    case 74: ret = 0; break;                                          // fsync
    case 82: {                                                        // rename
      try { fs.renameSync(cstr(a0), cstr(a1)); ret = 0; } catch (e) { ret = -1; }
      break;
    }
    case 83: {                                                        // mkdir
      try { fs.mkdirSync(cstr(a0)); ret = 0; } catch (e) { ret = (e.code === 'EEXIST') ? -17 : -1; }
      break;
    }
    case 87: {                                                        // unlink
      try { fs.unlinkSync(cstr(a0)); ret = 0; } catch (e) { ret = -1; }
      break;
    }
    case 35: ret = 0; break;                                          // nanosleep
    case 96: ret = 0; break;                                          // gettimeofday
    case 201: {                                                       // time
      ret = Math.floor(Date.now() / 1000) | 0;
      if (a0 !== 0) sw(a0, ret);
      break;
    }
    default:
      if (TRACE) console.error('unhandled syscall ' + num);
      ret = -38; // -ENOSYS
  }
  R[2] = ret | 0;   // return in $v0
}

// ---------------------------------------------------------------------------
// ELF loader
// ---------------------------------------------------------------------------
function loadElf(file) {
  const buf = fs.readFileSync(file);
  if (!(buf[0] === 0x7f && buf[1] === 0x45 && buf[2] === 0x4c && buf[3] === 0x46)) {
    throw new Error('not an ELF file');
  }
  const entry = buf.readUInt32LE(24);
  const phoff = buf.readUInt32LE(28);
  const phentsize = buf.readUInt16LE(42);
  const phnum = buf.readUInt16LE(44);
  const PT_LOAD = 1;
  for (let i = 0; i < phnum; i++) {
    const o = phoff + i * phentsize;
    const type = buf.readUInt32LE(o);
    if (type !== PT_LOAD) continue;
    const p_offset = buf.readUInt32LE(o + 4);
    const p_vaddr = buf.readUInt32LE(o + 8);
    const p_filesz = buf.readUInt32LE(o + 16);
    const p_memsz = buf.readUInt32LE(o + 20);
    if (p_filesz > 0) {
      buf.copy(mem, (p_vaddr - BASE) >>> 0, p_offset, p_offset + p_filesz);
    }
    // remaining [filesz, memsz) is bss, already zeroed by Buffer.alloc
    if (TRACE) console.error('LOAD vaddr=0x' + p_vaddr.toString(16) + ' filesz=0x' + p_filesz.toString(16) + ' memsz=0x' + p_memsz.toString(16));
  }
  return entry;
}

// ---------------------------------------------------------------------------
// Instruction execution
// ---------------------------------------------------------------------------
function step(inst) {
  const op = inst >>> 26;
  const rs = (inst >>> 21) & 31;
  const rt = (inst >>> 16) & 31;
  const rd = (inst >>> 11) & 31;
  const sa = (inst >>> 6) & 31;
  const funct = inst & 0x3f;
  const imm = inst & 0xffff;
  const simm = (imm << 16) >> 16;      // sign-extended
  let branch = -1;                     // >=0 means take branch to this target

  switch (op) {
    case 0x00: { // SPECIAL
      switch (funct) {
        case 0x00: w(rd, R[rt] << sa); break;                     // sll
        case 0x02:                                               // srl / rotr
          if ((inst >> 21) & 1) { w(rd, sa === 0 ? R[rt] : ((R[rt] >>> sa) | (R[rt] << (32 - sa)))); }
          else { w(rd, R[rt] >>> sa); }
          break;
        case 0x03: w(rd, R[rt] >> sa); break;                    // sra
        case 0x04: w(rd, R[rt] << (R[rs] & 31)); break;          // sllv
        case 0x06: {                                             // srlv / rotrv
          const s = R[rs] & 31;
          if ((inst >> 6) & 1) { w(rd, s === 0 ? R[rt] : ((R[rt] >>> s) | (R[rt] << (32 - s)))); }
          else { w(rd, R[rt] >>> s); }
          break;
        }
        case 0x07: w(rd, R[rt] >> (R[rs] & 31)); break;          // srav
        case 0x08: branch = R[rs] >>> 0; break;                  // jr
        case 0x09: w(rd === 0 ? 31 : rd, (pc + 8) | 0); branch = R[rs] >>> 0; break; // jalr
        case 0x0a: if (R[rt] === 0) w(rd, R[rs]); break;         // movz
        case 0x0b: if (R[rt] !== 0) w(rd, R[rs]); break;         // movn
        case 0x0c: doSyscall(); break;                           // syscall
        case 0x0d: break;                                        // break (ignored)
        case 0x10: w(rd, HI); break;                             // mfhi
        case 0x11: HI = R[rs]; break;                            // mthi
        case 0x12: w(rd, LO); break;                             // mflo
        case 0x13: LO = R[rs]; break;                            // mtlo
        case 0x18: multSigned(R[rs], R[rt]); break;              // mult
        case 0x19: multUnsigned(R[rs], R[rt]); break;            // multu
        case 0x1a: {                                             // div
          const a = R[rs], b = R[rt];
          if (b === 0) { LO = 0; HI = a; }
          else if (a === -2147483648 && b === -1) { LO = -2147483648; HI = 0; }
          else { const r = a % b; LO = ((a - r) / b) | 0; HI = r | 0; }
          break;
        }
        case 0x1b: {                                             // divu
          const a = R[rs] >>> 0, b = R[rt] >>> 0;
          if (b === 0) { LO = -1; HI = a | 0; }
          else { const r = a % b; LO = ((a - r) / b) | 0; HI = r | 0; }
          break;
        }
        case 0x20: w(rd, (R[rs] + R[rt]) | 0); break;            // add
        case 0x21: w(rd, (R[rs] + R[rt]) | 0); break;            // addu
        case 0x22: w(rd, (R[rs] - R[rt]) | 0); break;            // sub
        case 0x23: w(rd, (R[rs] - R[rt]) | 0); break;            // subu
        case 0x24: w(rd, R[rs] & R[rt]); break;                  // and
        case 0x25: w(rd, R[rs] | R[rt]); break;                  // or
        case 0x26: w(rd, R[rs] ^ R[rt]); break;                  // xor
        case 0x27: w(rd, ~(R[rs] | R[rt])); break;               // nor
        case 0x2a: w(rd, R[rs] < R[rt] ? 1 : 0); break;          // slt
        case 0x2b: w(rd, (R[rs] >>> 0) < (R[rt] >>> 0) ? 1 : 0); break; // sltu
        case 0x34: if (R[rs] === R[rt]) throw new Error('trap: teq @0x' + pc.toString(16)); break; // teq
        default: throw new Error('unknown SPECIAL funct 0x' + funct.toString(16) + ' @0x' + pc.toString(16));
      }
      break;
    }
    case 0x01: { // REGIMM
      switch (rt) {
        case 0x00: if (R[rs] < 0) branch = (npc + (simm << 2)) >>> 0; break;    // bltz
        case 0x01: if (R[rs] >= 0) branch = (npc + (simm << 2)) >>> 0; break;   // bgez
        case 0x10: w(31, (pc + 8) | 0); if (R[rs] < 0) branch = (npc + (simm << 2)) >>> 0; break;  // bltzal
        case 0x11: w(31, (pc + 8) | 0); if (R[rs] >= 0) branch = (npc + (simm << 2)) >>> 0; break; // bgezal
        default: throw new Error('unknown REGIMM rt 0x' + rt.toString(16) + ' @0x' + pc.toString(16));
      }
      break;
    }
    case 0x02: branch = ((npc & 0xf0000000) | ((inst & 0x03ffffff) << 2)) >>> 0; break;                 // j
    case 0x03: w(31, (pc + 8) | 0); branch = ((npc & 0xf0000000) | ((inst & 0x03ffffff) << 2)) >>> 0; break; // jal
    case 0x04: if (R[rs] === R[rt]) branch = (npc + (simm << 2)) >>> 0; break;    // beq
    case 0x05: if (R[rs] !== R[rt]) branch = (npc + (simm << 2)) >>> 0; break;    // bne
    case 0x06: if (R[rs] <= 0) branch = (npc + (simm << 2)) >>> 0; break;         // blez
    case 0x07: if (R[rs] > 0) branch = (npc + (simm << 2)) >>> 0; break;          // bgtz
    case 0x08: w(rt, (R[rs] + simm) | 0); break;                                  // addi
    case 0x09: w(rt, (R[rs] + simm) | 0); break;                                  // addiu
    case 0x0a: w(rt, R[rs] < simm ? 1 : 0); break;                                // slti
    case 0x0b: w(rt, (R[rs] >>> 0) < (simm >>> 0) ? 1 : 0); break;                // sltiu
    case 0x0c: w(rt, R[rs] & imm); break;                                         // andi
    case 0x0d: w(rt, R[rs] | imm); break;                                         // ori
    case 0x0e: w(rt, R[rs] ^ imm); break;                                         // xori
    case 0x0f: w(rt, (imm << 16) | 0); break;                                     // lui
    case 0x11: cop1(inst, rs, rt, rd, sa, funct); { branch = cop1Branch; cop1Branch = -1; } break; // COP1
    case 0x1c: { // SPECIAL2
      switch (funct) {
        case 0x02: w(rd, Math.imul(R[rs], R[rt])); break;        // mul
        case 0x00: { multSigned(R[rs], R[rt]); break; }          // madd (base) - handled below
        default: throw new Error('unknown SPECIAL2 funct 0x' + funct.toString(16) + ' @0x' + pc.toString(16));
      }
      break;
    }
    case 0x1f: { // SPECIAL3
      if (funct === 0x00) { // ext
        const size = rd + 1, lsb = sa;
        const maskv = size >= 32 ? 0xffffffff : ((1 << size) - 1);
        w(rt, (R[rs] >>> lsb) & maskv);
      } else if (funct === 0x04) { // ins
        const msb = rd, lsb = sa, size = msb - lsb + 1;
        const maskv = size >= 32 ? 0xffffffff : ((1 << size) - 1);
        const ins = (R[rs] & maskv) << lsb;
        const keep = ~(maskv << lsb);
        w(rt, (R[rt] & keep) | ins);
      } else if (funct === 0x20) { // BSHFL
        const v = R[rt];
        if (sa === 0x02) w(rd, (((v & 0x00ff00ff) << 8) | ((v >>> 8) & 0x00ff00ff)) | 0);   // wsbh
        else if (sa === 0x10) w(rd, (v << 24) >> 24);   // seb
        else if (sa === 0x18) w(rd, (v << 16) >> 16);   // seh
        else throw new Error('unknown BSHFL sa 0x' + sa.toString(16) + ' @0x' + pc.toString(16));
      } else {
        throw new Error('unknown SPECIAL3 funct 0x' + funct.toString(16) + ' @0x' + pc.toString(16));
      }
      break;
    }
    case 0x20: w(rt, lb(R[rs] + simm)); break;                    // lb
    case 0x21: w(rt, lh(R[rs] + simm)); break;                    // lh
    case 0x22: { // lwl
      const a = (R[rs] + simm) | 0, b = a & 3, wd = lw(a & ~3), s = 24 - 8 * b;
      const maskv = s === 0 ? 0 : (((1 << s) >>> 0) - 1);
      w(rt, ((wd << s) | (R[rt] & maskv)) | 0);
      break;
    }
    case 0x23: w(rt, lw(R[rs] + simm)); break;                    // lw
    case 0x24: w(rt, lbu(R[rs] + simm)); break;                   // lbu
    case 0x25: w(rt, lhu(R[rs] + simm)); break;                   // lhu
    case 0x26: { // lwr
      const a = (R[rs] + simm) | 0, b = a & 3, wd = lw(a & ~3), s = 8 * b;
      const keep = s === 0 ? 0 : (~(0xffffffff >>> s)) >>> 0;
      w(rt, ((wd >>> s) | (R[rt] & keep)) | 0);
      break;
    }
    case 0x28: sb(R[rs] + simm, R[rt]); break;                    // sb
    case 0x29: sh(R[rs] + simm, R[rt]); break;                    // sh
    case 0x2a: { // swl
      const a = (R[rs] + simm) | 0, b = a & 3, base = a & ~3, s = 24 - 8 * b;
      const memw = lw(base);
      const val = ((memw & (~((0xffffffff) >>> s) | 0)) | (R[rt] >>> s)) | 0;
      sw(base, val);
      break;
    }
    case 0x2b: sw(R[rs] + simm, R[rt]); break;                    // sw
    case 0x2e: { // swr
      const a = (R[rs] + simm) | 0, b = a & 3, base = a & ~3, s = 8 * b;
      const memw = lw(base);
      const lowmask = s === 0 ? 0 : (((1 << s) >>> 0) - 1);
      const val = ((memw & lowmask) | (R[rt] << s)) | 0;
      sw(base, val);
      break;
    }
    case 0x31: FGR[rt] = lw(R[rs] + simm); break;                 // lwc1
    case 0x35: { const a = R[rs] + simm; FGR[rt] = lw(a); FGR[rt + 1] = lw(a + 4); break; } // ldc1
    case 0x39: sw(R[rs] + simm, FGR[rt]); break;                  // swc1
    case 0x3d: { const a = R[rs] + simm; sw(a, FGR[rt]); sw(a + 4, FGR[rt + 1]); break; }   // sdc1
    default:
      throw new Error('unknown opcode 0x' + op.toString(16) + ' @0x' + pc.toString(16) + ' inst=0x' + (inst >>> 0).toString(16));
  }
  return branch;
}

// COP1 (floating point) --------------------------------------------------------
let cop1Branch = -1;
function cop1(inst, rs, rt, rd, sa, funct) {
  const fs_ = rd;        // fs in bits 15-11
  const ft = rt;         // ft in bits 20-16
  const fd = sa;         // fd in bits 10-6
  switch (rs) {
    case 0x00: w(rt, FGR[fs_]); return;                 // mfc1
    case 0x04: FGR[fs_] = R[rt]; return;                // mtc1
    case 0x03: w(rt, FGR[fs_ + 1]); return;             // mfhc1
    case 0x07: FGR[fs_ + 1] = R[rt]; return;            // mthc1
    case 0x02: w(rt, FGR[fs_]); return;                 // cfc1 (approx)
    case 0x06: return;                                  // ctc1 (ignored)
    case 0x08: {                                        // BC1
      const cc = (rt >>> 2) & 7;
      const tf = rt & 1;
      if ((FCC[cc] ? 1 : 0) === tf) cop1Branch = (npc + (simmOf(inst) << 2)) >>> 0;
      return;
    }
    case 0x10: fpArith(false, ft, fs_, fd, funct); return;   // S format
    case 0x11: fpArith(true, ft, fs_, fd, funct); return;    // D format
    case 0x14: { // W format (integer source)
      if (funct === 0x20) wS(fd, FGR[fs_] | 0);          // cvt.s.w
      else if (funct === 0x21) wD(fd, FGR[fs_] | 0);     // cvt.d.w
      else throw new Error('unknown COP1.W funct 0x' + funct.toString(16));
      return;
    }
    default: throw new Error('unknown COP1 rs 0x' + rs.toString(16) + ' @0x' + pc.toString(16));
  }
}
function simmOf(inst) { return ((inst & 0xffff) << 16) >> 16; }
function fpArith(isD, ft, fs_, fd, funct) {
  const a = isD ? rD(fs_) : rS(fs_);
  const bv = isD ? rD(ft) : rS(ft);
  const wr = isD ? wD : wS;
  switch (funct) {
    case 0x00: wr(fd, a + bv); return;   // add
    case 0x01: wr(fd, a - bv); return;   // sub
    case 0x02: wr(fd, a * bv); return;   // mul
    case 0x03: wr(fd, a / bv); return;   // div
    case 0x04: wr(fd, Math.sqrt(a)); return;   // sqrt
    case 0x05: wr(fd, Math.abs(a)); return;    // abs
    case 0x06: // mov
      if (isD) { FGR[fd] = FGR[fs_]; FGR[fd + 1] = FGR[fs_ + 1]; }
      else FGR[fd] = FGR[fs_];
      return;
    case 0x07: wr(fd, -a); return;             // neg
    case 0x0d: FGR[fd] = Math.trunc(a) | 0; return;  // trunc.w
    case 0x11: { // movcf (movt/movf)
      const cc = (ft >>> 2) & 7;
      const tf = ft & 1;
      if ((FCC[cc] ? 1 : 0) === tf) {
        if (isD) { FGR[fd] = FGR[fs_]; FGR[fd + 1] = FGR[fs_ + 1]; }
        else FGR[fd] = FGR[fs_];
      }
      return;
    }
    case 0x20: wS(fd, a); return;   // cvt.s (from D or W handled by caller); here D->S
    case 0x21: wD(fd, a); return;   // cvt.d (S->D)
    case 0x24: FGR[fd] = Math.trunc(a) | 0; return;  // cvt.w
    default:
      if (funct >= 0x30) { // C.cond
        const cc = (fd >>> 2) & 7;   // cc in bits 10-8
        const cond = funct & 0xf;
        let res;
        if (Number.isNaN(a) || Number.isNaN(bv)) res = (cond & 1) !== 0;
        else res = (((cond & 4) && a < bv) || ((cond & 2) && a === bv)) ? true : false;
        FCC[cc] = res ? 1 : 0;
        return;
      }
      throw new Error('unknown COP1 arith funct 0x' + funct.toString(16) + ' @0x' + pc.toString(16));
  }
}

// ---------------------------------------------------------------------------
// Main loop
// ---------------------------------------------------------------------------
function run(entry) {
  R[28] = GP_VALUE | 0;   // $gp
  R[29] = STACK_TOP | 0;  // $sp
  R[31] = 0;              // $ra
  R[4] = 0; R[5] = 0;     // argc/argv for main(0,0)
  pc = entry >>> 0;
  npc = (entry + 4) >>> 0;
  let count = 0;
  while (running) {
    const inst = lw(pc) | 0;
    const branch = step(inst);
    if (branch >= 0) {
      pc = npc;
      npc = branch >>> 0;
    } else {
      pc = npc;
      npc = (npc + 4) >>> 0;
    }
    count++;
    if (MAX_INSN && count >= MAX_INSN) {
      console.error('reached MAX_INSN=' + MAX_INSN + ' @pc=0x' + pc.toString(16));
      break;
    }
  }
  if (TRACE) console.error('executed ' + count + ' instructions');
}

// ---------------------------------------------------------------------------
const entry = loadElf(ELF_PATH);
if (TRACE) console.error('entry=0x' + entry.toString(16) + ' mem=' + (MEM_SIZE >>> 20) + 'MiB');
try {
  run(entry);
} catch (e) {
  console.error('VM error: ' + e.message);
  console.error(e.stack);
  process.exit(1);
}

#!/usr/bin/env node
/*
 * vm.js - A MIPS32r2 (little-endian, o32) interpreter that runs the
 * `doomgeneric_mips` ELF binary, servicing its system calls (the custom
 * numbering defined in doomgeneric/doomgeneric/my_stdlib.c) so that DOOM boots
 * and renders frames to /tmp/frame.bmp.
 *
 * Usage:  node vm.js [path-to-elf]
 *
 * Environment:
 *   DOOM_FRAMES   number of frames to save before exiting (default 1, 0 = run forever)
 *   DOOM_TRACE    if set, prints a syscall trace to stderr
 *   DOOM_MAXINSN  optional cap on executed instructions (0 = unlimited)
 */
'use strict';

const fs = require('fs');
const path = require('path');

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
const ELF_PATH = process.argv[2] || path.join(__dirname, 'doomgeneric_mips');
const TRACE = !!process.env.DOOM_TRACE;
const FRAME_TARGET = process.env.DOOM_FRAMES !== undefined ? parseInt(process.env.DOOM_FRAMES, 10) : 1;
const MAX_INSN = process.env.DOOM_MAXINSN ? parseInt(process.env.DOOM_MAXINSN, 10) : 0;

const BASE = 0x00400000;                 // lowest mapped virtual address
const MEM_TOP = 0x40c00000;              // top of address space (exclusive)
const MEM_SIZE = MEM_TOP - BASE;         // ~1.08 GiB flat memory
const STACK_TOP = 0x40bffff0;           // initial $sp (16-byte aligned)
const GP_VALUE = 0x0047d090;            // from .reginfo gp_value

// ---------------------------------------------------------------------------
// Memory
// ---------------------------------------------------------------------------
const mem = Buffer.alloc(MEM_SIZE);      // zero-filled (covers .bss)
const M = new Uint8Array(mem.buffer, mem.byteOffset, MEM_SIZE);
const dv = new DataView(mem.buffer, mem.byteOffset, MEM_SIZE);

function inRange(a) { return a >= BASE && a < MEM_TOP; }
function off(a) {
  const o = (a - BASE) >>> 0;
  if (a < BASE || o >= MEM_SIZE) throw new Error('memory access out of range @0x' + (a >>> 0).toString(16));
  return o;
}

function lb(a)  { return dv.getInt8(off(a)); }
function lbu(a) { return M[off(a)]; }
function lh(a)  { return dv.getInt16(off(a), true); }
function lhu(a) { return dv.getUint16(off(a), true); }
function lw(a)  { return dv.getInt32(off(a), true); }
function lwu(a) { return dv.getUint32(off(a), true); }
function sb(a, v) { M[off(a)] = v & 0xff; }
function sh(a, v) { dv.setUint16(off(a), v & 0xffff, true); }
function sw(a, v) { dv.setUint32(off(a), v >>> 0, true); }

// ---------------------------------------------------------------------------
// CPU state
// ---------------------------------------------------------------------------
const R = new Int32Array(32);   // general purpose registers
let HI = 0, LO = 0;
let pc = 0, npc = 0;

// FPU (COP1): 32 x 32-bit registers, 8 condition codes
const FGR = new Int32Array(32);
const FCC = new Uint8Array(8);
const fbuf = new DataView(new ArrayBuffer(8));
function rS(n) { fbuf.setInt32(0, FGR[n], true); return fbuf.getFloat32(0, true); }
function wS(n, v) { fbuf.setFloat32(0, v, true); FGR[n] = fbuf.getInt32(0, true); }
function rD(n) { fbuf.setInt32(0, FGR[n], true); fbuf.setInt32(4, FGR[n + 1], true); return fbuf.getFloat64(0, true); }
function wD(n, v) { fbuf.setFloat64(0, v, true); FGR[n] = fbuf.getInt32(0, true); FGR[n + 1] = fbuf.getInt32(4, true); }

function w(i, v) { if (i !== 0) R[i] = v; }   // write GPR (r0 stays 0)

// 64-bit multiply helpers producing signed HI/LO -------------------------------
function umul(aU, bU) {
  const aL = aU & 0xffff, aH = aU >>> 16;
  const bL = bU & 0xffff, bH = bU >>> 16;
  const ll = aL * bL;
  const lh_ = aL * bH;
  const hl = aH * bL;
  const hh = aH * bH;
  const cross = (ll >>> 16) + (lh_ & 0xffff) + (hl & 0xffff);
  const lo = ((ll & 0xffff) | ((cross & 0xffff) << 16)) >>> 0;
  const hi = (hh + (lh_ >>> 16) + (hl >>> 16) + (cross >>> 16)) >>> 0;
  return [hi, lo];
}
function multSigned(a, b) {
  const aU = a >>> 0, bU = b >>> 0;
  let [hi, lo] = umul(aU, bU);
  if (a < 0) hi = (hi - bU) >>> 0;
  if (b < 0) hi = (hi - aU) >>> 0;
  HI = hi | 0; LO = lo | 0;
}
function multUnsigned(a, b) {
  const [hi, lo] = umul(a >>> 0, b >>> 0);
  HI = hi | 0; LO = lo | 0;
}

// ---------------------------------------------------------------------------
// Host file descriptor table for guest syscalls
// ---------------------------------------------------------------------------
const fdTable = new Map();   // guestFd -> { hostFd, pos, path }
let nextFd = 3;
let framesSaved = 0;
let exitCode = 0;
let running = true;

function cstr(addr) {
  let p = off(addr), s = '';
  while (M[p] !== 0) { s += String.fromCharCode(M[p]); p++; }
  return s;
}

// guest open flags (see my_stdlib.c)
const GO_RDONLY = 0, GO_WRONLY = 1, GO_RDWR = 2, GO_CREAT = 64, GO_TRUNC = 512, GO_APPEND = 1024;

function guestOpen(pathAddr, flags) {
  const p = cstr(pathAddr);
  let hf = 0;
  const acc = flags & 3;
  if (acc === GO_WRONLY) hf |= fs.constants.O_WRONLY;
  else if (acc === GO_RDWR) hf |= fs.constants.O_RDWR;
  else hf |= fs.constants.O_RDONLY;
  if (flags & GO_CREAT) hf |= fs.constants.O_CREAT;
  if (flags & GO_TRUNC) hf |= fs.constants.O_TRUNC;
  if (flags & GO_APPEND) hf |= fs.constants.O_APPEND;
  let hostFd;
  try {
    hostFd = fs.openSync(p, hf, 0o644);
  } catch (e) {
    if (TRACE) console.error('open FAIL ' + p + ' -> ' + e.code);
    return -2; // -ENOENT
  }
  const gfd = nextFd++;
  fdTable.set(gfd, { hostFd, pos: 0, path: p });
  if (TRACE) console.error('open ' + p + ' flags=0x' + flags.toString(16) + ' -> fd ' + gfd);
  return gfd;
}

function guestRead(fd, bufAddr, count) {
  if (fd === 0) return 0; // stdin: EOF
  const info = fdTable.get(fd);
  if (!info) return -9; // -EBADF
  const o = off(bufAddr);
  let n;
  try {
    n = fs.readSync(info.hostFd, mem, o, count, info.pos);
  } catch (e) { return -5; }
  info.pos += n;
  return n;
}

function guestWrite(fd, bufAddr, count) {
  if (fd === 1 || fd === 2) {
    const o = off(bufAddr);
    const slice = mem.subarray(o, o + count);
    if (fd === 1) process.stdout.write(slice); else process.stderr.write(slice);
    return count;
  }
  const info = fdTable.get(fd);
  if (!info) return -9;
  const o = off(bufAddr);
  let n;
  try {
    n = fs.writeSync(info.hostFd, mem, o, count, info.pos);
  } catch (e) { return -5; }
  info.pos += n;
  // Detect a completed frame write and (optionally) stop.
  if (info.path && /frame\.bmp$/.test(info.path)) {
    framesSaved++;
    if (TRACE) console.error('frame ' + framesSaved + ' saved (' + n + ' bytes) to ' + info.path);
    if (FRAME_TARGET > 0 && framesSaved >= FRAME_TARGET) {
      try { fs.fsyncSync(info.hostFd); } catch (e) {}
      finish(0);
    }
  }
  return n;
}

function guestLseek(fd, offset, whence) {
  const info = fdTable.get(fd);
  if (!info) return -9;
  let np;
  if (whence === 0) np = offset;
  else if (whence === 1) np = info.pos + offset;
  else if (whence === 2) {
    let sz = 0;
    try { sz = fs.fstatSync(info.hostFd).size; } catch (e) {}
    np = sz + offset;
  } else return -22;
  if (np < 0) return -22;
  info.pos = np;
  return np;
}

function guestClose(fd) {
  const info = fdTable.get(fd);
  if (!info) return -9;
  try { fs.closeSync(info.hostFd); } catch (e) {}
  fdTable.delete(fd);
  return 0;
}

function finish(code) {
  running = false;
  exitCode = code | 0;
  // Flush guest std streams already written synchronously; just exit.
  process.exit(exitCode);
}

// System call dispatch. Numbers follow my_stdlib.c (x86-ish numbering that this
// binary reuses for the generic MIPS `syscall` instruction).
function doSyscall() {
  const num = R[2];                 // $v0
  const a0 = R[4], a1 = R[5], a2 = R[6];
  let ret = 0;
  switch (num) {
    case 0:  ret = guestRead(a0, a1, a2 >>> 0); break;               // read
    case 1:  ret = guestWrite(a0, a1, a2 >>> 0); break;              // write
    case 2:  ret = guestOpen(a0, a1); break;                          // open
    case 3:  ret = guestClose(a0); break;                             // close
    case 8:  ret = guestLseek(a0, a1, a2); break;                     // lseek
    case 60: finish(a0); ret = 0; break;                              // exit
    case 74: ret = 0; break;                                          // fsync
    case 82: {                                                        // rename
      try { fs.renameSync(cstr(a0), cstr(a1)); ret = 0; } catch (e) { ret = -1; }
      break;
    }
    case 83: {                                                        // mkdir
      try { fs.mkdirSync(cstr(a0)); ret = 0; } catch (e) { ret = (e.code === 'EEXIST') ? -17 : -1; }
      break;
    }
    case 87: {                                                        // unlink
      try { fs.unlinkSync(cstr(a0)); ret = 0; } catch (e) { ret = -1; }
      break;
    }
    case 35: ret = 0; break;                                          // nanosleep
    case 96: ret = 0; break;                                          // gettimeofday
    case 201: {                                                       // time
      ret = Math.floor(Date.now() / 1000) | 0;
      if (a0 !== 0) sw(a0, ret);
      break;
    }
    default:
      if (TRACE) console.error('unhandled syscall ' + num);
      ret = -38; // -ENOSYS
  }
  R[2] = ret | 0;   // return in $v0
}

// ---------------------------------------------------------------------------
// ELF loader
// ---------------------------------------------------------------------------
function loadElf(file) {
  const buf = fs.readFileSync(file);
  if (!(buf[0] === 0x7f && buf[1] === 0x45 && buf[2] === 0x4c && buf[3] === 0x46)) {
    throw new Error('not an ELF file');
  }
  const entry = buf.readUInt32LE(24);
  const phoff = buf.readUInt32LE(28);
  const phentsize = buf.readUInt16LE(42);
  const phnum = buf.readUInt16LE(44);
  const PT_LOAD = 1;
  for (let i = 0; i < phnum; i++) {
    const o = phoff + i * phentsize;
    const type = buf.readUInt32LE(o);
    if (type !== PT_LOAD) continue;
    const p_offset = buf.readUInt32LE(o + 4);
    const p_vaddr = buf.readUInt32LE(o + 8);
    const p_filesz = buf.readUInt32LE(o + 16);
    const p_memsz = buf.readUInt32LE(o + 20);
    if (p_filesz > 0) {
      buf.copy(mem, (p_vaddr - BASE) >>> 0, p_offset, p_offset + p_filesz);
    }
    // remaining [filesz, memsz) is bss, already zeroed by Buffer.alloc
    if (TRACE) console.error('LOAD vaddr=0x' + p_vaddr.toString(16) + ' filesz=0x' + p_filesz.toString(16) + ' memsz=0x' + p_memsz.toString(16));
  }
  return entry;
}

// ---------------------------------------------------------------------------
// Instruction execution
