      throw new Error('unknown opcode 0x' + op.toString(16) + ' @0x' + pc.toString(16) + ' inst=0x' + (inst >>> 0).toString(16));
  }
  return branch;
}

// COP1 (floating point) --------------------------------------------------------
let cop1Branch = -1;
function cop1(inst, rs, rt, rd, sa, funct) {
  const fs_ = rd;        // fs in bits 15-11
  const ft = rt;         // ft in bits 20-16
  const fd = sa;         // fd in bits 10-6
  switch (rs) {
    case 0x00: w(rt, FGR[fs_]); return;                 // mfc1
    case 0x04: FGR[fs_] = R[rt]; return;                // mtc1
    case 0x03: w(rt, FGR[fs_ + 1]); return;             // mfhc1
    case 0x07: FGR[fs_ + 1] = R[rt]; return;            // mthc1
    case 0x02: w(rt, FGR[fs_]); return;                 // cfc1 (approx)
    case 0x06: return;                                  // ctc1 (ignored)
    case 0x08: {                                        // BC1
      const cc = (rt >>> 2) & 7;
      const tf = rt & 1;
      if ((FCC[cc] ? 1 : 0) === tf) cop1Branch = (npc + (simmOf(inst) << 2)) >>> 0;
      return;
    }
    case 0x10: fpArith(false, ft, fs_, fd, funct); return;   // S format
    case 0x11: fpArith(true, ft, fs_, fd, funct); return;    // D format
    case 0x14: { // W format (integer source)
      if (funct === 0x20) wS(fd, FGR[fs_] | 0);          // cvt.s.w
      else if (funct === 0x21) wD(fd, FGR[fs_] | 0);     // cvt.d.w
      else throw new Error('unknown COP1.W funct 0x' + funct.toString(16));
      return;
    }
    default: throw new Error('unknown COP1 rs 0x' + rs.toString(16) + ' @0x' + pc.toString(16));
  }
}
function simmOf(inst) { return ((inst & 0xffff) << 16) >> 16; }
function fpArith(isD, ft, fs_, fd, funct) {
  const a = isD ? rD(fs_) : rS(fs_);
  const bv = isD ? rD(ft) : rS(ft);
  const wr = isD ? wD : wS;
  switch (funct) {
    case 0x00: wr(fd, a + bv); return;   // add
    case 0x01: wr(fd, a - bv); return;   // sub
    case 0x02: wr(fd, a * bv); return;   // mul
    case 0x03: wr(fd, a / bv); return;   // div
    case 0x04: wr(fd, Math.sqrt(a)); return;   // sqrt
    case 0x05: wr(fd, Math.abs(a)); return;    // abs
    case 0x06: // mov
      if (isD) { FGR[fd] = FGR[fs_]; FGR[fd + 1] = FGR[fs_ + 1]; }
      else FGR[fd] = FGR[fs_];
      return;
    case 0x07: wr(fd, -a); return;             // neg
    case 0x0d: FGR[fd] = Math.trunc(a) | 0; return;  // trunc.w
    case 0x11: { // movcf (movt/movf)
      const cc = (ft >>> 2) & 7;
      const tf = ft & 1;
      if ((FCC[cc] ? 1 : 0) === tf) {
        if (isD) { FGR[fd] = FGR[fs_]; FGR[fd + 1] = FGR[fs_ + 1]; }
        else FGR[fd] = FGR[fs_];
      }
      return;
    }
    case 0x20: wS(fd, a); return;   // cvt.s (from D or W handled by caller); here D->S
    case 0x21: wD(fd, a); return;   // cvt.d (S->D)
    case 0x24: FGR[fd] = Math.trunc(a) | 0; return;  // cvt.w
    default:
      if (funct >= 0x30) { // C.cond
        const cc = (fd >>> 2) & 7;   // cc in bits 10-8
        const cond = funct & 0xf;
        let res;
        if (Number.isNaN(a) || Number.isNaN(bv)) res = (cond & 1) !== 0;
        else res = (((cond & 4) && a < bv) || ((cond & 2) && a === bv)) ? true : false;
        FCC[cc] = res ? 1 : 0;
        return;
      }
      throw new Error('unknown COP1 arith funct 0x' + funct.toString(16) + ' @0x' + pc.toString(16));
  }
}

// ---------------------------------------------------------------------------
// Main loop
// ---------------------------------------------------------------------------
function run(entry) {
  R[28] = GP_VALUE | 0;   // $gp
  R[29] = STACK_TOP | 0;  // $sp
  R[31] = 0;              // $ra
  R[4] = 0; R[5] = 0;     // argc/argv for main(0,0)
  pc = entry >>> 0;
