    case 0:  ret = guestRead(a0, a1, a2 >>> 0); break;               // read
    case 1:  ret = guestWrite(a0, a1, a2 >>> 0); break;              // write
    case 2:  ret = guestOpen(a0, a1); break;                          // open
    case 3:  ret = guestClose(a0); break;                             // close
    case 8:  ret = guestLseek(a0, a1, a2); break;                     // lseek
